using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Set up options with a known resolver that only handles WeatherForecast.
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly.
JsonTypeInfo<WeatherForecast> typedInfo = (JsonTypeInfo<WeatherForecast>)options.GetTypeInfo(typeof(WeatherForecast));
Console.WriteLine($"Got JsonTypeInfo<WeatherForecast>: Type = {typedInfo.Type.Name}");

// 2) Probe without throwing: TryGetTypeInfo returns false if metadata isn't available.
//    Use a resolver that resolves nothing to demonstrate the "not available" path.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new EmptyResolver()
};

bool found = limited.TryGetTypeInfo(typeof(WeatherForecast), out JsonTypeInfo? probeResult);
if (found)
    Console.WriteLine($"Probe found metadata: {probeResult!.Type.Name}");
else
    Console.WriteLine("Probe: metadata NOT available for WeatherForecast (no exception thrown).");

record WeatherForecast(DateTime Date, int TemperatureC, string? Summary);

// A resolver that deliberately resolves nothing — simulates "type not registered".
sealed class EmptyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options) => null;
}

